@using sv_fb9be070b2544c8e8188b800b4b4d022.Services

@inject ISettingsService SettingsService

<div class="change-password-panel">
    <button class="btn btn-outline-secondary w-100 text-start d-flex justify-content-between align-items-center"
            @onclick="ToggleExpanded">
        <span>🔑 Change Password</span>
        <span class="expand-icon">@(IsExpanded ? "▲" : "▼")</span>
    </button>

    @if (IsExpanded)
    {
        <div class="password-form mt-3 p-3 border rounded">
            @if (!string.IsNullOrEmpty(_errorMessage))
            {
                <div class="alert alert-danger py-2">@_errorMessage</div>
            }
            @if (!string.IsNullOrEmpty(_successMessage))
            {
                <div class="alert alert-success py-2">@_successMessage</div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>
            <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_isSaving">
                @(_isSaving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    private bool IsExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _errorMessage;
    private string? _successMessage;
    private bool _isSaving;

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task UpdatePassword()
    {
        _errorMessage = null;
        _successMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword)
            || string.IsNullOrWhiteSpace(_newPassword))
        {
            _errorMessage = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _errorMessage = "New password and confirmation do not match.";
            return;
        }

        if (_newPassword.Length < 8)
        {
            _errorMessage = "New password must be at least 8 characters.";
            return;
        }

        _isSaving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _successMessage = "Password updated successfully.";
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to update password: {ex.Message}";
        }
        finally
        {
            _isSaving = false;
        }
    }
}

@using sv_fb9be070b2544c8e8188b800b4b4d022.Models

<div class="modal-backdrop-custom @(Visible ? "show" : "")" @onclick="Cancel">
    <div class="modal-dialog-custom" @onclick:stopPropagation="true">
        <div class="modal-header-custom">
            <h5>Revoke Session</h5>
