{"file_text": "@using sv_fb9be070b2544c8e8188b800b4b4d022.Models
@using sv_fb9be070b2544c8e8188b800b4b4d022.Services

@inject ISettingsService SettingsService

<div class="settings-section">
    <h4>Security</h4>
    <p class="text-muted">Manage your account security</p>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }
    else
    {
        <div class="mb-4">
            <ChangePasswordPanel />
        </div>

        <div class="mb-4">
            <h6>Two-Factor Authentication</h6>
            <div class="d-flex align-items-center gap-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="twoFactor">Enable 2FA</label>
                </div>
                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            @if (_lastPasswordChange.HasValue)
            {
                <p class="small text-muted mt-2">
                    Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }
        </div>

        <div class="mb-4">
            <h6>Active Sessions</h6>
            <div class="table-responsive">
                <table class="table table-sm table-hover">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _sessions)
                        {
                            var isCurrent = session == _sessions.FirstOrDefault();
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-primary ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => ShowRevokeDialog(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>

        @if (_revokeTarget is not null)
        {
            <RevokeSessionDialog Visible="true"
                                 Session="_revokeTarget"
                                 OnConfirm="ConfirmRevoke"
                                 OnCancel="CancelRevoke" />
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private ActiveSession? _revokeTarget;

    protected override async Task OnInitializedAsync()
    {
        await LoadSecurity();
    }

    private async Task LoadSecurity()
    {
        _loading = true;
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _revokeTarget = session;
    }

    private async Task ConfirmRevoke()
    {
        if (_revokeTarget is not null)
        {
            await SettingsService.RevokeSessionAsync(_revokeTarget.Id);
            _revokeTarget = null;
            await LoadSecurity();
        }
    }

    private void CancelRevoke()
    {
        _revokeTarget = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
