toolArgs.file_text:
@using sv_fb9be070b2544c8e8188b800b4b4d022.Models
@using sv_fb9be070b2544c8e8188b800b4b4d022.Services

@inject ISettingsService SettingsService

<div class="settings-section">
    <h4>Appearance</h4>
    <p class="text-muted">Customize how the app looks and feels</p>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success py-2 alert-dismissible">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-6">
                <div class="mb-4">
                    <h6>Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6>Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"font-{size}")"
                                   value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"font-{size}")">@size</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6>Language</h6>
                    <select class="form-select" @bind="_language">
                        <option value="English">English</option>
                        <option value="Spanish">Spanish</option>
                        <option value="French">French</option>
                        <option value="German">German</option>
                        <option value="Japanese">Japanese</option>
                        <option value="Chinese">Chinese</option>
                    </select>
                </div>

                <div class="mb-4">
                    <h6>Compact Mode</h6>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@_compactMode"
                               @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                        <label class="form-check-label" for="compactMode">
                            Enable compact mode
                        </label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save")
                </button>
            </div>

            <div class="col-md-6">
                <h6>Live Preview</h6>
                <div class="live-preview @GetPreviewClasses()">
                    <div class="preview-header">
                        <strong>App Header</strong>
                        <span class="preview-badge">@_language</span>
                    </div>
                    <div class="preview-content">
                        <p class="preview-title">Dashboard</p>
                        <p>This is a preview of how your selected appearance options will look.</p>
                        <div class="preview-card">
                            <span>Sample Card</span>
                            <span class="preview-badge">Active</span>
                        </div>
                        <div class="preview-card">
                            <span>Another Card</span>
                            <span class="preview-badge">Pending</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _message;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var classes = $"preview-theme-{_theme.ToLowerInvariant()} preview-font-{_fontSize.ToLowerInvariant()}";
        if (_compactMode) classes += " preview-compact";
        return classes;
    }

    private async Task Save()
    {
        _saving = true;
        _message = null;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _message = "Appearance settings saved!";
        _saving = false;
    }
}

