}

/* ===== Settings Dashboard Layout ===== */

.settings-dashboard {
    display: flex;
    gap: 0;
    min-height: 70vh;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

/* ===== Sidebar ===== */

.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem;
    margin-bottom: 1rem;
    font-weight: 600;
    color: #495057;
}

.settings-nav {
    display: flex;
    flex-direction: column;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    border: none;
    background: transparent;
    text-align: left;
    font-size: 0.95rem;
    color: #495057;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
}

.settings-nav-item:hover {
    background-color: #e9ecef;
}

.settings-nav-item.active {
    background-color: #0d6efd;
    color: #fff;
    font-weight: 500;
}

.nav-icon {
    font-size: 1.1rem;
}

/* ===== Content Area ===== */

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

.settings-section h4 {
    margin-bottom: 0.25rem;
    font-weight: 600;
}

/* ===== Profile Avatar ===== */

.avatar-preview {
    padding: 1rem;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    background: #f8f9fa;
}

.avatar-img {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

/* ===== Revoke Session Dialog ===== */

.modal-backdrop-custom {
    display: none;
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.5);
    z-index: 1050;
    justify-content: center;
    align-items: center;
}

.modal-backdrop-custom.show {
    display: flex;
}

.modal-dialog-custom {
    background: #fff;
    border-radius: 8px;
    width: 100%;
    max-width: 440px;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
    overflow: hidden;
}

.modal-header-custom {
    padding: 1rem 1.25rem;
    border-bottom: 1px solid #dee2e6;
}

    .modal-header-custom h5 {
        margin: 0;
        font-weight: 600;
    }

.modal-body-custom {
    padding: 1.25rem;
}

    .modal-body-custom p {
        margin-bottom: 0.5rem;
    }

.modal-footer-custom {
    padding: 0.75rem 1.25rem;
    border-top: 1px solid #dee2e6;
    display: flex;
    justify-content: flex-end;
    gap: 0.5rem;
}

/* ===== Appearance Live Preview ===== */

.live-preview {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    transition: all 0.2s ease;
}

.preview-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
}

.preview-content {
    padding: 1rem;
}

.preview-title {
    font-weight: 600;
    margin-bottom: 0.5rem;
}

.preview-card {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.preview-badge {
    font-size: 0.75rem;
    padding: 0.2rem 0.5rem;
    border-radius: 4px;
    background: #0d6efd;
    color: #fff;
}

/* Theme variants */
.preview-theme-light {
    background: #ffffff;
    color: #212529;
}

    .preview-theme-light .preview-header {
        background: #f8f9fa;
    }

.preview-theme-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

    .preview-theme-dark .preview-header {
        background: #2a2a3d;
        border-color: #444;
    }

    .preview-theme-dark .preview-card {
        border-color: #555;
        background: #2a2a3d;
    }

.preview-theme-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

    .preview-theme-system .preview-header {
        background: #f0f0f0;
    }

/* Font sizes */
.preview-font-small {
    font-size: 0.8rem;
}

.preview-font-medium {
    font-size: 0.95rem;
}

.preview-font-large {
    font-size: 1.15rem;
}

/* Compact mode */
.preview-compact .preview-content {
    padding: 0.5rem;
}

.preview-compact .preview-card {
    padding: 0.25rem 0.5rem;
    margin-bottom: 0.25rem;
}

.preview-compact .preview-header {
    padding: 0.4rem 0.75rem;
}

/* ===== Change Password Panel ===== */

.expand-icon {
    font-size: 0.75rem;
}

/* ===== Responsive ===== */

@@media (max-width: 768px) {
    .settings-dashboard {
        flex-direction: column;
    }

    .settings-sidebar {
        width: 100%;
        min-width: unset;
        border-right: none;
        border-bottom: 1px solid #dee2e6;
    }

    .settings-nav {
        flex-direction: row;
        overflow-x: auto;
    }

    .settings-nav-item {
        white-space: nowrap;
    }
}

